function solve(n: number, edges: number[][]): number {
    // Build adjacency list
    const adj: Map<number, { to: number; start: number; end: number }[]> = new Map();
    for (const [u, v, s, e] of edges) {
        if (!adj.has(u)) {
            adj.set(u, []);
        }
        adj.get(u)!.push({ to: v, start: s, end: e });
    }

    // Dijkstra's algorithm with priority queue
    const pq: [number, number][] = [[0, 0]]; // [time, node]
    const dist: Map<number, number> = new Map();
    dist.set(0, 0);

    while (pq.length > 0) {
        // Extract the node with the smallest time
        pq.sort((a, b) => a[0] - b[0]);
        const [time, node] = pq.shift()!;

        // If we've already found a better time for this node, skip
        if (dist.get(node) !== time) {
            continue;
        }

        // If we've reached the destination
        if (node === n - 1) {
            return time;
        }

        // Try to move along each outgoing edge
        if (adj.has(node)) {
            for (const edge of adj.get(node)!) {
                const { to, start, end } = edge;
                // Check if the edge is available at current time
                if (start <= time && time <= end) {
                    // We can take this edge, move to the next node
                    const newTime = time + 1;
                    if (!dist.has(to) || newTime < dist.get(to)!) {
                        dist.set(to, newTime);
                        pq.push([newTime, to]);
                    }
                }
            }
        }

        // Also consider staying at the current node
        if (!dist.has(node) || time < dist.get(node)!) {
            dist.set(node, time);
            pq.push([time, node]);
        }
    }

    // If we can't reach the destination
    return -1;
}

