    val dist = new mutable.HashMap[Long, Long]()

    dist(0) = 0

    while (pq.nonEmpty) {
        val arr = pq.dequeue()
        val time = arr(0)
        val node = arr(1)

        if (dist.contains(node) && dist(node) < time) {
            continue
        }

        if (node == n - 1) {
            return time
        }

        if (adj.contains(node)) {
            for (edge <- adj(node)) {
                val v = edge(0)
                val s = edge(1)
                val e = edge(2)
                if (s <= time && time <= e) {
                    val newTime = time + 1
                    if (!dist.contains(v) || newTime < dist(v)) {
                        dist(v) = newTime
                        pq.enqueue(Array(newTime, v))
                    }
                }
            }
        }

        if (!dist.contains(node) || time < dist(node)) {
            dist(node) = time
            pq.enqueue(Array(time, node))
        }
    }

    -1
}
